  1→import { AbsoluteFill, useCurrentFrame, useVideoConfig } from "remotion";
  2→import {
  3→  COLORS,
  4→  GRADIENTS,
  5→  fadeIn,
  6→  fadeOut,
  7→  slideUp,
  8→  typewriter,
  9→  gradientText,
 10→  pulseGlow,
 11→} from "../animations";
 12→
 13→// Scene 1: Hook — "Le SEO est mort" (0-8s = 240 frames)
 14→export const Scene1_Hook: React.FC = () => {
 15→  const frame = useCurrentFrame();
 16→  const { fps } = useVideoConfig();
 17→
 18→  // Phase 1: "Le SEO est mort." dramatic entrance (0-90)
 19→  const seoOpacity = fadeIn(frame, 10, 15);
 20→  const seoY = slideUp(frame, 10, 20);
 21→  const seoStrike = frame > 60 ? 1 : 0;
 22→
 23→  // Phase 2: Stats appear (90-180)
 24→  const statOpacity = fadeIn(frame, 95, 20);
 25→  const statY = slideUp(frame, 95, 25);
 26→
 27→  // Phase 3: "Vos clients ne cherchent plus..." (130-240)
 28→  const questionOpacity = fadeIn(frame, 140, 20);
 29→  const questionY = slideUp(frame, 140, 25);
 30→
 31→  // Global fade out
 32→  const globalFadeOut = fadeOut(frame, 215, 25);
 33→
 34→  // Particle grid background
 35→  const gridDots = [];
 36→  for (let x = 0; x < 20; x++) {
 37→    for (let y = 0; y < 12; y++) {
 38→      const delay = (x + y) * 2;
 39→      const dotOpacity = fadeIn(frame, delay, 40) * 0.08 * pulseGlow(frame + delay, 0.03, 0.3, 1);
 40→      gridDots.push(
 41→        <div
 42→          key={`${x}-${y}`}
 43→          style={{
 44→            position: "absolute",
 45→            left: x * 100 + 50,
 46→            top: y * 100 + 30,
 47→            width: 3,
 48→            height: 3,
 49→            borderRadius: "50%",
 50→            background: COLORS.purple,
 51→            opacity: dotOpacity,
 52→          }}
 53→        />
 54→      );
 55→    }
 56→  }
 57→
 58→  return (
 59→    <AbsoluteFill
 60→      style={{
 61→        background: GRADIENTS.darkRadial,
 62→        justifyContent: "center",
 63→        alignItems: "center",
 64→        fontFamily: "'Inter', 'Segoe UI', sans-serif",
 65→        opacity: globalFadeOut,
 66→      }}
 67→    >
 68→      {/* Grid background */}
 69→      {gridDots}
 70→
 71→      {/* Ambient glow */}
 72→      <div
 73→        style={{
 74→          position: "absolute",
 75→          width: 600,
 76→          height: 600,
 77→          borderRadius: "50%",
 78→          background: "radial-gradient(circle, rgba(168,85,247,0.08) 0%, transparent 70%)",
 79→          top: "50%",
 80→          left: "50%",
 81→          transform: "translate(-50%, -50%)",
 82→          opacity: pulseGlow(frame, 0.04, 0.5, 1),
 83→        }}
 84→      />
 85→
 86→      <div style={{ textAlign: "center", position: "relative", zIndex: 2 }}>
 87→        {/* "Le SEO est mort." */}
 88→        <div
 89→          style={{
 90→            opacity: seoOpacity,
 91→            transform: `translateY(${seoY}px)`,
 92→            position: "relative",
 93→          }}
 94→        >
 95→          <span
 96→            style={{
 97→              fontSize: 110,
 98→              fontWeight: 800,
 99→              color: COLORS.white,
100→              letterSpacing: -3,
101→              lineHeight: 1.1,
102→            }}
103→          >
104→            Le SEO est{" "}
105→            <span style={{ position: "relative", display: "inline-block" }}>
106→              <span
107→                style={{
108→                  ...gradientText(GRADIENTS.rose),
109→                  fontSize: 110,
110→                  fontWeight: 800,
111→                }}
112→              >
113→                mort
114→              </span>
115→              {/* Strike-through animation */}
116→              <div
117→                style={{
118→                  position: "absolute",
119→                  top: "55%",
120→                  left: -10,
121→                  height: 6,
122→                  background: COLORS.rose,
123→                  borderRadius: 3,
124→                  width: seoStrike
125→                    ? `${Math.min((frame - 60) * 15, 110)}%`
126→                    : "0%",
127→                  boxShadow: `0 0 20px ${COLORS.rose}`,
128→                }}
129→              />
130→            </span>
131→            .
132→          </span>
133→        </div>
134→
135→        {/* Stat: 50% des recherches → IA d'ici 2026 */}
136→        <div
137→          style={{
138→            opacity: statOpacity,
139→            transform: `translateY(${statY}px)`,
140→            marginTop: 60,
141→            display: "flex",
142→            justifyContent: "center",
143→            gap: 50,
144→          }}
145→        >
146→          <StatBadge value="50%" label="des recherches vont aux IA" color={COLORS.purple} />
147→          <StatBadge value="0" label="clics necessaires" color={COLORS.rose} suffix=" clic" />
148→          <StatBadge value="3x" label="plus de conversions" color={COLORS.green} />
149→        </div>
150→
151→        {/* Question line */}
152→        <div
153→          style={{
154→            opacity: questionOpacity,
155→            transform: `translateY(${questionY}px)`,
156→            marginTop: 60,
157→            fontSize: 36,
158→            color: COLORS.gray,
159→            fontWeight: 400,
160→            letterSpacing: 0.5,
161→          }}
162→        >
163→          {typewriter(
164→            "Vos clients ne cherchent plus sur Google. Ils demandent aux IA.",
165→            frame,
166→            145,
167→            1.2
168→          )}
169→          <span
170→            style={{
171→              opacity: pulseGlow(frame, 0.1, 0, 1),
172→              color: COLORS.purple,
173→            }}
174→          >
175→            |
176→          </span>
177→        </div>
178→      </div>
179→    </AbsoluteFill>
180→  );
181→};
182→
183→// Sub-component: stat badge
184→const StatBadge: React.FC<{
185→  value: string;
186→  label: string;
187→  color: string;
188→  suffix?: string;
189→}> = ({ value, label, color }) => (
190→  <div
191→    style={{
192→      display: "flex",
193→      flexDirection: "column",
194→      alignItems: "center",
195→      padding: "20px 30px",
196→      borderRadius: 16,
197→      background: `rgba(${hexToRgb(color)}, 0.08)`,
198→      border: `1px solid rgba(${hexToRgb(color)}, 0.2)`,
199→    }}
200→  >
201→    <span
202→      style={{
203→        fontSize: 52,
204→        fontWeight: 800,
205→        color,
206→        letterSpacing: -1,
207→      }}
208→    >
209→      {value}
210→    </span>
211→    <span
212→      style={{
213→        fontSize: 18,
214→        color: COLORS.gray,
215→        marginTop: 4,
216→        maxWidth: 160,
217→        textAlign: "center",
218→        lineHeight: 1.3,
219→      }}
220→    >
221→      {label}
222→    </span>
223→  </div>
224→);
225→
226→function hexToRgb(hex: string): string {
227→  const r = parseInt(hex.slice(1, 3), 16);
228→  const g = parseInt(hex.slice(3, 5), 16);
229→  const b = parseInt(hex.slice(5, 7), 16);
230→  return `${r},${g},${b}`;
231→}
