  1→import { AbsoluteFill, useCurrentFrame, useVideoConfig, interpolate, Easing } from "remotion";
  2→import {
  3→  COLORS,
  4→  GRADIENTS,
  5→  fadeIn,
  6→  fadeOut,
  7→  slideUp,
  8→  slideDown,
  9→  gradientText,
 10→  scaleSpring,
 11→  pulseGlow,
 12→  typewriter,
 13→} from "../animations";
 14→
 15→// Scene 5: CTA & Closing (8s = 240 frames)
 16→export const Scene5_CTA: React.FC = () => {
 17→  const frame = useCurrentFrame();
 18→  const { fps } = useVideoConfig();
 19→
 20→  // Phase 1: "Pret a etre cite ?" (0-60)
 21→  const headOpacity = fadeIn(frame, 10, 20);
 22→  const headY = slideUp(frame, 10, 25);
 23→
 24→  // Phase 2: Value props recap (50-130)
 25→  const props = [
 26→    { icon: "⚡", text: "Audit gratuit en 30 secondes" },
 27→    { icon: "💳", text: "0 carte bancaire requise" },
 28→    { icon: "🇫🇷", text: "Made in France — RGPD" },
 29→  ];
 30→
 31→  // Phase 3: CTA button (110-180)
 32→  const ctaOpacity = fadeIn(frame, 115, 20);
 33→  const ctaScale = scaleSpring(frame, fps, 115);
 34→  const ctaPulse = pulseGlow(frame, 0.06, 0.7, 1);
 35→
 36→  // Phase 4: URL (150-240)
 37→  const urlOpacity = fadeIn(frame, 155, 20);
 38→  const urlY = slideUp(frame, 155, 20);
 39→
 40→  // Phase 5: Trust badges (170-240)
 41→  const trustOpacity = fadeIn(frame, 175, 20);
 42→
 43→  // Particles rising
 44→  const particles = Array.from({ length: 30 }, (_, i) => {
 45→    const x = 100 + (i * 61) % 1720;
 46→    const speed = 0.5 + (i % 5) * 0.3;
 47→    const size = 2 + (i % 3);
 48→    const startY = 1100 - ((frame * speed + i * 40) % 1200);
 49→    const particleOpacity = interpolate(startY, [0, 200, 900, 1100], [0, 0.3, 0.3, 0], {
 50→      extrapolateLeft: "clamp",
 51→      extrapolateRight: "clamp",
 52→    });
 53→    return (
 54→      <div
 55→        key={i}
 56→        style={{
 57→          position: "absolute",
 58→          left: x,
 59→          top: startY,
 60→          width: size,
 61→          height: size,
 62→          borderRadius: "50%",
 63→          background: i % 3 === 0 ? COLORS.purple : i % 3 === 1 ? COLORS.violet : COLORS.rose,
 64→          opacity: particleOpacity * 0.4,
 65→        }}
 66→      />
 67→    );
 68→  });
 69→
 70→  return (
 71→    <AbsoluteFill
 72→      style={{
 73→        background: GRADIENTS.darkRadial,
 74→        justifyContent: "center",
 75→        alignItems: "center",
 76→        fontFamily: "'Inter', 'Segoe UI', sans-serif",
 77→      }}
 78→    >
 79→      {/* Rising particles */}
 80→      {particles}
 81→
 82→      {/* Large background glow */}
 83→      <div
 84→        style={{
 85→          position: "absolute",
 86→          width: 1000,
 87→          height: 1000,
 88→          borderRadius: "50%",
 89→          background: "radial-gradient(circle, rgba(168,85,247,0.1) 0%, transparent 60%)",
 90→          top: "50%",
 91→          left: "50%",
 92→          transform: "translate(-50%, -50%)",
 93→          opacity: pulseGlow(frame, 0.03, 0.5, 1),
 94→        }}
 95→      />
 96→
 97→      <div style={{ textAlign: "center", position: "relative", zIndex: 2, maxWidth: 1200 }}>
 98→        {/* Headline */}
 99→        <div
100→          style={{
101→            opacity: headOpacity,
102→            transform: `translateY(${headY}px)`,
103→          }}
104→        >
105→          <div
106→            style={{
107→              fontSize: 80,
108→              fontWeight: 800,
109→              color: COLORS.white,
110→              letterSpacing: -3,
111→              lineHeight: 1.15,
112→            }}
113→          >
114→            Pret a etre{" "}
115→            <span style={{ ...gradientText(GRADIENTS.brand), fontSize: 80, fontWeight: 800 }}>
116→              cite
117→            </span>{" "}
118→            ?
119→          </div>
120→        </div>
121→
122→        {/* Value props */}
123→        <div
124→          style={{
125→            display: "flex",
126→            justifyContent: "center",
127→            gap: 40,
128→            marginTop: 50,
129→          }}
130→        >
131→          {props.map((prop, i) => {
132→            const delay = 55 + i * 15;
133→            const propOpacity = fadeIn(frame, delay, 20);
134→            const propY = slideUp(frame, delay, 20);
135→            return (
136→              <div
137→                key={prop.text}
138→                style={{
139→                  opacity: propOpacity,
140→                  transform: `translateY(${propY}px)`,
141→                  display: "flex",
142→                  alignItems: "center",
143→                  gap: 12,
144→                  fontSize: 22,
145→                  color: COLORS.grayLight,
146→                  fontWeight: 500,
147→                }}
148→              >
149→                <span style={{ fontSize: 28 }}>{prop.icon}</span>
150→                {prop.text}
151→              </div>
152→            );
153→          })}
154→        </div>
155→
156→        {/* CTA Button */}
157→        <div
158→          style={{
159→            opacity: ctaOpacity,
160→            transform: `scale(${ctaScale})`,
161→            marginTop: 60,
162→          }}
163→        >
164→          <div
165→            style={{
166→              display: "inline-block",
167→              padding: "22px 70px",
168→              borderRadius: 16,
169→              background: GRADIENTS.brand,
170→              boxShadow: `0 0 ${40 * ctaPulse}px rgba(168,85,247,${0.4 * ctaPulse}), 0 10px 40px rgba(0,0,0,0.3)`,
171→              fontSize: 26,
172→              fontWeight: 700,
173→              color: COLORS.white,
174→              letterSpacing: 0.5,
175→            }}
176→          >
177→            Lancer mon audit gratuit →
178→          </div>
179→        </div>
180→
181→        {/* URL */}
182→        <div
183→          style={{
184→            opacity: urlOpacity,
185→            transform: `translateY(${urlY}px)`,
186→            marginTop: 35,
187→          }}
188→        >
189→          <span
190→            style={{
191→              ...gradientText(GRADIENTS.brand),
192→              fontSize: 42,
193→              fontWeight: 700,
194→              letterSpacing: 1,
195→            }}
196→          >
197→            citedby.ai
198→          </span>
199→        </div>
200→
201→        {/* Trust badges */}
202→        <div
203→          style={{
204→            opacity: trustOpacity,
205→            marginTop: 40,
206→            display: "flex",
207→            justifyContent: "center",
208→            gap: 30,
209→          }}
210→        >
211→          {["RGPD Compliant", "SSL Encrypted", "99.9% Uptime", "Made in France"].map((badge, i) => (
212→            <div
213→              key={badge}
214→              style={{
215→                padding: "8px 18px",
216→                borderRadius: 8,
217→                border: "1px solid rgba(168,85,247,0.15)",
218→                background: "rgba(168,85,247,0.05)",
219→                fontSize: 14,
220→                color: COLORS.grayDark,
221→                fontWeight: 500,
222→              }}
223→            >
224→              {badge}
225→            </div>
226→          ))}
227→        </div>
228→      </div>
229→    </AbsoluteFill>
230→  );
231→};
